mapper.select:

WHERE t.delete_flg = 0

  AND t.status = #{status}


  AND LOWER(t.title) LIKE CONCAT('%', LOWER(#{search}), '%')


  AND t.priority = #{priority}

ORDER BY t.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM tasks t
WHERE t.delete_flg = 0

  AND t.status = #{status}


  AND LOWER(t.title) LIKE CONCAT('%', LOWER(#{search}), '%')


  AND t.priority = #{priority}
